258			if shouldCollect("actions", opts.IncludeResources) {
259				g.Go(func() error {
260					actions, err := c.client.GetActions(ctx, bpID)
261					if err != nil {
262						// Silent skip for expected errors
263						if !strings.Contains(err.Error(), "410 Gone") {
264							return fmt.Errorf("failed to get actions for blueprint %s: %w", bpID, err)
265						}
266						return nil
267					}
268	
269					mu.Lock()
270					data.Actions = append(data.Actions, actions...)
271					mu.Unlock()
