285							}
286							mu.Lock()
287							data.ActionPermissions[aID] = perms
288							mu.Unlock()
289							return nil
290						})
291					}
292					return nil
293				})
294			}
295	
296			// Collect blueprint permissions
297			if shouldCollect("blueprint-permissions", opts.IncludeResources) || len(opts.IncludeResources) == 0 {
298				bpIDCopy := bpID // capture for goroutine closure
299				g.Go(func() error {
300					perms, err := c.client.GetBlueprintPermissions(ctx, bpIDCopy)
301					if err != nil {
302						// Non-fatal: permissions fetch failure should not abort the export
303						return nil
304					}
305					mu.Lock()
306					data.BlueprintPermissions[bpIDCopy] = perms
307					mu.Unlock()
308					return nil
309				})
310			}
311		}
312	
313		// Collect organization-wide resources
314		if !opts.SkipEntities && shouldCollect("teams", opts.IncludeResources) {
315			g.Go(func() error {
316				teams, err := c.client.GetTeams(ctx)
317				if err != nil {
318					return fmt.Errorf("failed to get teams: %w", err)
319				}
320	
321				mu.Lock()
322				data.Teams = teams
323				mu.Unlock()
324				return nil
325			})
326		}
327	
328		// Collect users
329		if !opts.SkipEntities && shouldCollect("users", opts.IncludeResources) {
330			g.Go(func() error {
331				users, err := c.client.GetUsers(ctx)
332				if err != nil {
333					return fmt.Errorf("failed to get users: %w", err)
334				}
335	
336				mu.Lock()
337				data.Users = users
338				mu.Unlock()
339				return nil
340			})
341		}
342	
343		// Collect organization-wide automations (via GetAllActions) and merge into actions
344		if shouldCollect("actions", opts.IncludeResources) || shouldCollect("automations", opts.IncludeResources) {
345			g.Go(func() error {
346				allActions, err := c.client.GetAllActions(ctx)
347				if err != nil {
348					return fmt.Errorf("failed to get all actions/automations: %w", err)
349				}
350	
351				mu.Lock()
352				data.Actions = append(data.Actions, allActions...)
353				mu.Unlock()
354	
355				// Fetch permissions for each org-wide action
356				for _, action := range allActions {
357					actionID, ok := action["identifier"].(string)
358					if !ok {
359						continue
360					}
361					aID := actionID // capture for goroutine closure
362					g.Go(func() error {
363						perms, err := c.client.GetActionPermissions(ctx, aID)
364						if err != nil {
365							// Non-fatal: skip silently
366							return nil
367						}
368						mu.Lock()
369						data.ActionPermissions[aID] = perms
370						mu.Unlock()
371						return nil
372					})
373				}
374				return nil
375			})
376		}
377	
378		if shouldCollect("pages", opts.IncludeResources) {
379			g.Go(func() error {
380				folders, err := c.client.GetFolders(ctx)
381				if err != nil {
382					return fmt.Errorf("failed to get folders: %w", err)
383				}
384				pages, err := c.client.GetPages(ctx)
385				if err != nil {
386					return fmt.Errorf("failed to get pages: %w", err)
387				}
388	
389				mu.Lock()
390				data.Folders = folders
391				data.Pages = pages
392				mu.Unlock()
393				return nil
394			})
395		}
396	
397		if shouldCollect("integrations", opts.IncludeResources) {
398			g.Go(func() error {
399				integrations, err := c.client.GetIntegrations(ctx)
400				if err != nil {
401					return fmt.Errorf("failed to get integrations: %w", err)
402				}
403	
404				mu.Lock()
405				data.Integrations = integrations
406				mu.Unlock()
407				return nil
408			})
409		}
410	
411		// Wait for all goroutines to complete
412		if err := g.Wait(); err != nil {
413			return nil, err
414		}
415	
416		// Attach timeout errors to data
417		data.TimeoutErrors = timeoutErrors
418	
419		return data, nil
420	}
421	
422	// ApplyBlueprintExclusions returns two filtered slices from all:
423	//   - iterList: used to iterate for fetching entities/scorecards/actions (deep-excluded removed, schema-only kept)
424	//   - dataList: written to data.Blueprints for export output (both deep and schema-only excluded)
425	func ApplyBlueprintExclusions(all []api.Blueprint, excludeDeep, excludeSchema []string) (iterList, dataList []api.Blueprint) {
426		if len(excludeDeep) == 0 && len(excludeSchema) == 0 {
427			return all, all
428		}
429		deepSet := make(map[string]bool, len(excludeDeep))
430		for _, id := range excludeDeep {
431			deepSet[id] = true
432		}
433		schemaSet := make(map[string]bool, len(excludeSchema))
434		for _, id := range excludeSchema {
435			schemaSet[id] = true
436		}
437	
438		for _, bp := range all {
439			id, _ := bp["identifier"].(string)
440			if deepSet[id] {
441				// Deep exclusion: skip in both lists
442				continue
443			}
444			// In iteration list (fetches dependent resources) for everyone not deep-excluded
445			iterList = append(iterList, bp)
446			if schemaSet[id] {
447				// Schema-only exclusion: skip in data (output) list only
448				continue
449			}
450			dataList = append(dataList, bp)
451		}
452		return iterList, dataList
453	}
